-- Seed terms for KipGo (versión 2.0 - Junio 2026)
-- Incluye: CLIENT, OWNER, STAFF, PRIVACY

INSERT INTO terms (id, type, version, content, "isActive", "createdAt") VALUES
(
  gen_random_uuid()::text,
  'client',
  '2.0',
  E'TÉRMINOS Y CONDICIONES — USUARIO\n\nÚltima actualización: Mayo 2026\n\n1. ACEPTACIÓN DE LOS TÉRMINOS\nAl acceder o utilizar la aplicación KipGo ("la Plataforma"), usted acepta cumplir y estar legalmente vinculado por estos Términos y Condiciones. Si no está de acuerdo con alguna parte, no debe utilizar nuestros servicios.\n\n2. DESCRIPCIÓN DEL SERVICIO\nKipGo es una plataforma que conecta a viajeros con tiendas locales para el almacenamiento temporal de equipaje. Actuamos como intermediario facilitando las reservas, pagos y comunicación entre usuarios y anfitriones. No prestamos directamente el servicio de almacenamiento, sino que facilitamos la transacción entre las partes.\n\n3. REGISTRO Y CUENTA\n3.1. Para utilizar la Plataforma debe crear una cuenta proporcionando información veraz y completa.\n3.2. Usted es responsable de mantener la confidencialidad de sus credenciales de acceso.\n3.3. Debe notificar inmediatamente cualquier uso no autorizado de su cuenta.\n3.4. KipGo se reserva el derecho de verificar su identidad y rechazar registros sin expresión de causa.\n\n4. RESERVAS Y PAGOS\n4.1. Al realizar una reserva, autoriza el cargo del monto total correspondiente.\n4.2. Los precios se muestran en pesos chilenos (CLP) e incluyen IVA cuando corresponda.\n4.3. El pago se procesa al momento de la reserva a través de Stripe.\n4.4. Las extensiones de tiempo están sujetas a disponibilidad y cargos adicionales.\n4.5. El comprobante de pago se envía automáticamente por correo electrónico.\n\n5. CANCELACIONES Y REEMBOLSOS\n5.1. Cancelaciones realizadas antes del check-in: reembolso completo del monto pagado.\n5.2. Cancelaciones después del check-in: no aplica reembolso.\n5.3. El reembolso se procesa dentro de los 5-10 días hábiles al método de pago original.\n5.4. KipGo se reserva el derecho de cancelar reservas por causas de fuerza mayor, con reembolso completo.\n\n6. ARTÍCULOS PROHIBIDOS\nQueda estrictamente prohibido almacenar:\n- Armas, explosivos o materiales inflamables\n- Sustancias ilegales o contrabando\n- Alimentos perecederos o animales vivos\n- Dinero en efectivo, joyas u objetos de valor declarado superior a $2.500 USD\n- Documentos personales originales (pasaportes, cédulas, etc.)\n- Cualquier artículo cuya tenencia sea ilegal según la legislación chilena\n\n7. OBLIGACIONES DEL USUARIO\n7.1. Proporcionar información precisa sobre el contenido de su equipaje.\n7.2. Retirar el equipaje dentro del período contratado.\n7.3. Cumplir con las normas y horarios del establecimiento anfitrión.\n7.4. Indemnizar a KipGo y al anfitrión por daños causados por el incumplimiento de estas condiciones.\n\n8. DECLARACIÓN DE VALOR\n8.1. El usuario puede declarar un valor superior para su equipaje, lo que proporciona cobertura adicional.\n8.2. La falta de declaración limita la responsabilidad máxima al monto total pagado por la reserva.\n8.3. KipGo no será responsable por artículos no declarados cuyo valor exceda $2.500 USD.\n\n9. LIMITACIÓN DE RESPONSABILIDAD\n9.1. KipGo actúa únicamente como facilitador de la transacción entre el usuario y el anfitrión.\n9.2. La responsabilidad de KipGo se limita al monto total pagado por la reserva en cuestión.\n9.3. KipGo no será responsable por daños indirectos, pérdida de oportunidades o lucro cesante.\n9.4. El anfitrión es responsable directo del cuidado y custodia del equipaje durante el período de almacenamiento.\n\n10. PROPIEDAD INTELECTUAL\nTodos los derechos de propiedad intelectual sobre la Plataforma, incluyendo su diseño, logotipos, marcas y contenido, son propiedad de KipGo. Queda prohibida la reproducción, distribución o modificación no autorizada.\n\n11. TERMINACIÓN\nKipGo puede suspender o terminar su cuenta en caso de:\n- Violación de estos términos\n- Actividad fraudulenta o ilegal\n- Conducta que pueda dañar a otros usuarios o a la Plataforma\n- Inactividad prolongada de la cuenta\n\n12. LEY APLICABLE Y JURISDICCIÓN\nEstos Términos se rigen por las leyes de la República de Chile. Cualquier controversia será sometida a los tribunales ordinarios de justicia de Santiago, Chile.\n\n13. MODIFICACIONES\nKipGo se reserva el derecho de modificar estos términos en cualquier momento. Los cambios serán notificados a través de la aplicación o por correo electrónico. El uso continuado de la Plataforma después de las modificaciones constituye aceptación de los nuevos términos.\n\n14. CONTACTO\nPara consultas sobre estos términos: legal@kipgo.app',
  true,
  NOW()
),
(
  gen_random_uuid()::text,
  'owner',
  '2.0',
  E'TÉRMINOS Y CONDICIONES — ANFITRIÓN\n\nÚltima actualización: Mayo 2026\n\n1. OBLIGACIONES DEL ANFITRIÓN\n1.1. Proporcionar información precisa sobre su ubicación, capacidad, horarios y precios.\n1.2. Mantener un área de almacenamiento segura, limpia y accesible.\n1.3. Aceptar y honrar todas las reservas confirmadas a través de la Plataforma.\n1.4. Estar disponible durante el horario comercial declarado para realizar check-in y check-out.\n1.5. Verificar la identidad del usuario antes de entregar el equipaje.\n1.6. Tomar fotografías del equipaje durante el check-in para respaldo.\n\n2. COMISIONES Y PAGOS\n2.1. KipGo cobra una comisión del 15% sobre cada reserva completada.\n2.2. Los pagos se procesan dentro de los 2 días hábiles posteriores al check-out.\n2.3. Los pagos se realizan a través de Stripe Connect a la cuenta bancaria registrada.\n2.4. El anfitrión es responsable del pago de impuestos asociados a sus ingresos según la legislación chilena.\n2.5. KipGo emitirá una factura electrónica por la comisión cobrada.\n\n3. SEGUROS Y RESPONSABILIDAD\n3.1. Cada reserva está cubierta por la póliza de protección de KipGo hasta $2.500 USD.\n3.2. El anfitrión debe contar con su propio seguro comercial para su establecimiento.\n3.3. El anfitrión es responsable directo del cuidado del equipaje durante el período de almacenamiento.\n3.4. Cualquier pérdida, daño o incidente debe ser reportado dentro de las 24 horas siguientes.\n3.5. El anfitrión acepta colaborar en la investigación de cualquier reclamo presentado por un usuario.\n\n4. OPERACIÓN DEL LOCAL\n4.1. Mantener actualizada la disponibilidad en tiempo real.\n4.2. Los precios pueden ser modificados en cualquier momento, pero las reservas ya confirmadas se respetan al precio original.\n4.3. El anfitrión solo puede cancelar reservas en circunstancias excepcionales debidamente justificadas.\n4.4. Las cancelaciones por parte del anfitrión pueden resultar en una penalización.\n\n5. PROHIBICIONES\nEl anfitrión no debe:\n- Discriminar a usuarios por razón de raza, género, religión, orientación sexual o nacionalidad\n- Solicitar pagos fuera de la Plataforma\n- Modificar precios después de una reserva confirmada\n- Almacenar artículos prohibidos\n\n6. TERMINACIÓN\nKipGo puede suspender o terminar la cuenta del anfitrión por:\n- Violaciones reiteradas de estos términos\n- Actividad fraudulenta\n- Calificaciones promedio inferiores al mínimo establecido\n- Proporcionar información falsa\n- Incumplimiento de las obligaciones de custodia\n\n7. EXCLUSIVIDAD\nDurante la vigencia de este acuerdo, el anfitrión se compromete a no publicar su espacio de almacenamiento en plataformas competidoras sin autorización previa por escrito de KipGo.\n\n8. LEY APLICABLE\nEstos términos se rigen por las leyes de la República de Chile. Para consultas: legal@kipgo.app',
  true,
  NOW()
),
(
  gen_random_uuid()::text,
  'staff',
  '2.0',
  E'TÉRMINOS Y CONDICIONES — PERSONAL\n\nÚltima actualización: Mayo 2026\n\n1. ALCANCE DEL ACCESO\nComo miembro del personal, se le otorga acceso limitado para:\n- Visualizar reservas de la ubicación asignada\n- Realizar check-in y check-out de equipaje\n- Comunicarse con los clientes respecto a sus reservas\n- Tomar fotografías de respaldo del equipaje\n\n2. RESPONSABILIDADES\n- Usar la aplicación únicamente para fines autorizados\n- Verificar la identidad del cliente antes de entregar artículos\n- Registrar con precisión los horarios de check-in y check-out\n- Reportar cualquier incidencia al anfitrión inmediatamente\n\n3. RESTRICCIONES\nEl personal NO puede:\n- Acceder o modificar la configuración o precios de la tienda\n- Visualizar datos financieros o de ingresos\n- Crear, cancelar o modificar reservas\n- Invitar o gestionar otros miembros del personal\n- Compartir sus credenciales de acceso con terceros\n\n4. RESPONSABILIDAD\n- El anfitrión es responsable por las acciones del personal bajo su supervisión\n- Las violaciones pueden resultar en la terminación inmediata del acceso\n- KipGo no es responsable por acciones del personal\n- El acceso puede ser revocado en cualquier momento por el anfitrión\n\n5. PRIVACIDAD\n- Los datos de clientes solo pueden ser accedidos para fines operativos\n- La información de los clientes debe mantenerse estrictamente confidencial\n- No utilizar datos de clientes para fines fuera del rol asignado\n\n6. LEY APLICABLE\nEstos términos se rigen por las leyes de la República de Chile.',
  true,
  NOW()
),
(
  gen_random_uuid()::text,
  'privacy',
  '2.0',
  E'POLÍTICA DE PRIVACIDAD\n\nÚltima actualización: Mayo 2026\n\n1. IDENTIDAD DEL RESPONSABLE\nKipGo SpA, rol único tributario: por definir, domicilio: Santiago, Chile. Correo electrónico: privacy@kipgo.app.\n\n2. INFORMACIÓN QUE RECOPILAMOS\n\n2.1. Información proporcionada por el usuario:\n- Nombre completo, correo electrónico, número de teléfono\n- Datos de perfil (foto, preferencias)\n- Información de facturación\n\n2.2. Información recopilada automáticamente:\n- Tipo de dispositivo, sistema operativo, modelo\n- Dirección IP, ubicación geográfica aproximada\n- Historial de reservas y uso de la aplicación\n- Identificadores de notificaciones push\n\n2.3. Información de pago:\nLos pagos son procesados por Stripe, Inc. KipGo no almacena números completos de tarjetas de crédito ni datos bancarios sensibles.\n\n3. FINALIDAD DEL TRATAMIENTO\nSus datos personales serán tratados para:\n- Procesar y gestionar reservas y pagos\n- Enviar confirmaciones, recibos y notificaciones relacionadas con el servicio\n- Proveer soporte al cliente y resolver incidencias\n- Mejorar y personalizar la experiencia del usuario\n- Cumplir con obligaciones legales y regulatorias\n- Prevenir fraudes y garantizar la seguridad de la Plataforma\n\n4. BASE LEGAL\nEl tratamiento de sus datos se basa en:\n- La ejecución del contrato de servicios (Ley N° 19.628)\n- Su consentimiento explícito\n- El interés legítimo de KipGo para mejorar sus servicios\n- Obligaciones legales aplicables\n\n5. DESTINATARIOS DE LOS DATOS\nCompartimos sus datos únicamente con:\n- Anfitriones/tiendas: datos necesarios para procesar la reserva\n- Stripe: procesamiento de pagos\n- Resend: envío de correos electrónicos transaccionales\n- Google Cloud Platform: alojamiento de datos\n- Expo: notificaciones push\n\nNo vendemos su información personal a terceros bajo ninguna circunstancia.\n\n6. TRANSFERENCIAS INTERNACIONALES\nSus datos pueden ser transferidos a servidores en Estados Unidos, los cuales cumplen con estándares de protección equivalentes a la legislación chilena.\n\n7. PLAZOS DE CONSERVACIÓN\nConservamos sus datos mientras su cuenta esté activa y durante 3 años después de su última actividad. Los datos de pago se conservan según los plazos establecidos por la legislación tributaria chilena.\n\n8. DERECHOS DEL TITULAR (Ley N° 19.628)\nUsted tiene derecho a:\n- Acceder: solicitar información sobre sus datos tratados\n- Rectificar: solicitar la corrección de datos inexactos\n- Cancelar: solicitar la eliminación de sus datos\n- Oponerse: oponerse al tratamiento para fines específicos\n\nPara ejercer estos derechos, envíe un correo a privacy@kipgo.app con el asunto "Derechos ARCO". Responderemos dentro de los 15 días hábiles.\n\n9. SEGURIDAD DE LOS DATOS\nImplementamos:\n- Cifrado AES-256 para datos en reposo\n- TLS 1.3 para datos en tránsito\n- Autenticación de dos factores para accesos administrativos\n- Auditorías periódicas de seguridad\n\n10. MENORES DE EDAD\nLa Plataforma está destinada a mayores de 18 años. No recopilamos intencionadamente datos de menores.\n\n11. MODIFICACIONES\nLos cambios serán notificados a través de la aplicación o por correo electrónico con al menos 15 días de anticipación.\n\n12. CONTACTO\nConsulta de privacidad: privacy@kipgo.app\nConsultas legales: legal@kipgo.app\n\n13. RECLAMOS ANTE AUTORIDAD\nPuede presentar un reclamo ante el Consejo para la Transparencia de Chile (www.consejotransparencia.cl).',
  true,
  NOW()
);
